<template>
  <q-layout view="lHh Lpr lFf">
    <q-header elevated>
      <q-toolbar>
        <q-btn flat dense round icon="menu" aria-label="Menu" @click="toggleLeftDrawer" />

        <q-toolbar-title>
         Admin site
        </q-toolbar-title>

        <div>v1.0.0</div>
        <q-btn flat dense round icon="logout" aria-label="Menu" @click="logout" />
      </q-toolbar>
    </q-header>

    <q-drawer v-model="leftDrawerOpen" show-if-above bordered>
      <q-list>
        <q-item-label header>
          Actions
        </q-item-label>

        <EssentialLink v-for="link in actionLinks" :key="link.title" v-bind="link" />
      </q-list>

      <q-list>
        <q-item-label header>
          DB tables
        </q-item-label>
        <EssentialLink v-for="link in essentialLinks" :key="essentialLinks.length+link.title" v-bind="link" />
      </q-list>
    </q-drawer>

    <q-page-container>
      <router-view :key="$route.fullPath" />
    </q-page-container>
  </q-layout>
</template>

<script lang="ts">
import { defineComponent, ref } from 'vue';
import { getAllComponents } from '../components/actions';
import ModelRegistry from '../models'
import AuthService from '../services/auth'
import EssentialLink from '../components/EssentialLink.vue'
const models = ModelRegistry.getInstance().getModels()


export default defineComponent({
  name: 'AdminLayout',

  components: {
    EssentialLink
  },

  setup() {
    const leftDrawerOpen = ref(false)
    return {
      // essentialLinks: linksList,
      // actionLinks: actionList,
      leftDrawerOpen,
      toggleLeftDrawer() {
        leftDrawerOpen.value = !leftDrawerOpen.value
      }
    }
  },
  computed:{
    essentialLinks(){
      var linkList= Object.keys(models).map((key) => ({
      title: key,
      caption: key,
      icon: models[key].META.icon,
      link: `/admin/${key.replace(/([a-z](?=[A-Z]))/g, '$1-').toLowerCase()}`
    }));

    linkList.unshift({
      title: 'Dashboard',
      caption: 'dashboard',
      icon: 'dashboard',
      link: '/admin/dashboard'
    })
    return linkList
    },
    actionLinks(){
      return Object.keys(getAllComponents()).map((obj:any)=>{
              return {
                title: obj,
                caption: obj.toLowerCase(),
                icon: 'dashboard',
                link: `/admin/${obj}`
              }
      })
    }
  },
  methods: {
    async logout() {
      await new AuthService().logout()
        .then(() => {
          this.$router.push({ name: 'home' })
        })
    }
  }
});
</script>
